  const initMem={learnedKeywords:{},categoryTimes:{"Order Creation":0.5,"Stock Check":0.25,"Stocktake":1.0,"Cancel Order":0.25,"Client Request":0.5,"Inwards/Receipt":0.5,"Dispatch Query":0.25,"Returns":0.5,"Compliance/H&S":0.5,"Internal":0.25,"Other":0.25},clientPatterns:{},history:[]};
  const [emailMem,setEmailMem]=useState(()=>{try{const v=window._emailMem;return v?{...initMem,...JSON.parse(v)}:{...initMem};}catch(e){return{...initMem};}});
  const mem=emailMem||initMem;const [emailMonth,setEmailMonth]=useState(`${now.getFullYear()}-${pad(now.getMonth()+1)}`);const emailRef=useRef();
  const [skuClients,setSkuClients]=useState(()=>{try{const v=window._skuClients;return v?JSON.parse(v):{};}catch(e){return{};}});
  const [skuActive,setSkuActive]=useState("");const [skuNewName,setSkuNewName]=useState("");const [skuInwards,setSkuInwards]=useState([]);const [skuPaste,setSkuPaste]=useState("");const [skuFilter,setSkuFilter]=useState("all");const [skuSearch,setSkuSearch]=useState("");const skuMRef=useRef();const skuIRef=useRef();
  const saveSku=(d)=>{setSkuClients(d);try{window._skuClients=JSON.stringify(d);}catch(e){}};
  const saveMem=(m)=>{setEmailMem(m);window._emailMem=JSON.stringify(m);};
  const classify=(subj,from,body)=>{const t=(subj+" "+from+" "+(body||"")).toLowerCase();for(const[kw,cat]of Object.entries(mem.learnedKeywords)){if(t.includes(kw.toLowerCase()))return cat;}for(const[ck,kws]of Object.entries(DKW)){const cn=EMAIL_CATS.find(c=>c.toLowerCase()===ck)||"Other";for(const kw of kws){if(t.includes(kw.toLowerCase()))return cn;}}return"Other";};
  const defTime=(cat)=>mem.categoryTimes[cat]??0.25;
  const detectClient=(from,subj)=>{for(const[p,cl]of Object.entries(mem.clientPatterns)){if(from.toLowerCase().includes(p.toLowerCase()))return cl;}const m=from.match(/@([^.]+)/);return m?m[1].charAt(0).toUpperCase()+m[1].slice(1):"Unknown";};

  const handleSkuMaster=useCallback((e)=>{const file=e.target.files[0];if(!file)return;const cn=skuNewName.trim()||skuActive||file.name.replace(/\.[^.]+$/,"");const ext=file.name.split(".").pop().toLowerCase();
    const proc=(rows,hds)=>{const sc=findCol(hds,["SKU","sku","Item Code","ItemCode","Material","Product Code","Barcode","Article"]),dc=findCol(hds,["ItemDescription","Item Description","Description","Product Name","Name"]),uc=findCol(hds,["InvUOM","UOM","Unit"]),upc=findCol(hds,["UPC","EAN","Barcode","GTIN"]),tb=findCol(hds,["Trackbys","TrackBy","Track By"]),tr=findCol(hds,["TrackbyReq","TrackBy Required","Track By Required"]),d2=findCol(hds,["Description2","Description 2","Desc2"]),du=findCol(hds,["DIMUOM","Dim UOM"]),un=findCol(hds,["NumofInvUnits","Units Per"]),wt=findCol(hds,["WeightKgs","Weight"]);
      const mr=rows.map(r=>{const s=String(r[sc]||"").trim();if(!s)return null;return{sku:s,desc:dc?String(r[dc]||"").trim():"",uom:uc?String(r[uc]||"").trim():"",upc:upc?String(r[upc]||"").trim():"",trackby:tb?String(r[tb]||"").trim():"",trackbyReq:tr?String(r[tr]||"").trim():"",desc2:d2?String(r[d2]||"").trim():"",dimUom:du?String(r[du]||"").trim():"",units:un?r[un]:"",weight:wt?r[wt]:""};}).filter(Boolean);
      const up={...skuClients,[cn]:{skus:mr,fileName:file.name,loadedAt:new Date().toISOString(),count:mr.length}};saveSku(up);setSkuActive(cn);setSkuNewName("");};
    if(ext==="csv"){Papa.parse(file,{header:true,skipEmptyLines:true,complete:(r)=>{proc(r.data,r.meta.fields||[]);}});}
    else{const rd=new FileReader();rd.onload=(ev)=>{const wb=XLSX.read(ev.target.result,{type:"array"});let sn=wb.SheetNames[0];for(const s of wb.SheetNames){const l=s.toLowerCase();if(l.includes("master")||l.includes("sku")||l.includes("client"))sn=s;}const json=XLSX.utils.sheet_to_json(wb.Sheets[sn],{defval:""});proc(json,json.length?Object.keys(json[0]):[]);};rd.readAsArrayBuffer(file);}e.target.value="";},[skuClients,skuActive,skuNewName]);

  const runCheck=(list)=>{const cl=skuClients[skuActive];if(!cl)return;const mm={};cl.skus.forEach(m=>{mm[m.sku.toUpperCase().trim()]=m;});
    setSkuInwards(list.map((s,i)=>{const mt=mm[s.toUpperCase().trim()];return{id:i,sku:s,status:mt?"On Master":"Needs Creating",desc:mt?.desc||"",uom:mt?.uom||"",upc:mt?.upc||"",trackby:mt?.trackby||"",trackbyReq:mt?.trackbyReq||"Not found",desc2:mt?.desc2||""};}));};

  const handleSkuInFile=useCallback((e)=>{const file=e.target.files[0];if(!file)return;const ext=file.name.split(".").pop().toLowerCase();
    const proc=(rows,hds)=>{const sc=findCol(hds,["SKU","sku","Item Code","ItemCode","Material","Product Code","Barcode","Article"])||hds[0];runCheck(rows.map(r=>String(r[sc]||"").trim()).filter(Boolean));};
    if(ext==="csv"){Papa.parse(file,{header:true,skipEmptyLines:true,complete:(r)=>{proc(r.data,r.meta.fields||[]);}});}
    else{const rd=new FileReader();rd.onload=(ev)=>{const wb=XLSX.read(ev.target.result,{type:"array"});const json=XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]],{defval:""});proc(json,json.length?Object.keys(json[0]):[]);};rd.readAsArrayBuffer(file);}e.target.value="";},[skuClients,skuActive]);

