  const saveProf=(n)=>{if(!n.trim())return;const p={...cnzProfiles,[n.trim()]:{...cnzMap,_cc:cnzContainerCol}};setCnzProfiles(p);window._cnzProfiles=JSON.stringify(p);};
  const loadProf=(n)=>{const p=cnzProfiles[n];if(!p)return;const m={...p};const cc=m._cc||"";delete m._cc;setCnzMap(m);setCnzContainerCol(cc);};
  const delProf=(n)=>{const p={...cnzProfiles};delete p[n];setCnzProfiles(p);window._cnzProfiles=JSON.stringify(p);};
  const handleCnzFile=useCallback((e)=>{const file=e.target.files[0];if(!file)return;setCnzFile(file.name);setCnzPreview(false);const ext=file.name.split(".").pop().toLowerCase();
    if(ext==="csv"){Papa.parse(file,{header:true,skipEmptyLines:true,complete:(r)=>{setCnzCols(r.meta.fields||[]);setCnzSrc(r.data);setCnzMap(cnzAutoMap(r.meta.fields||[]));setCnzContainer(cnzExtractContainer(file.name));setCnzContainerCol("");}});}
    else{const rd=new FileReader();rd.onload=(ev)=>{const wb=XLSX.read(ev.target.result,{type:"array"});const ws=wb.Sheets[wb.SheetNames[0]];const json=XLSX.utils.sheet_to_json(ws,{defval:""});const cols=json.length?Object.keys(json[0]):[];setCnzCols(cols);setCnzSrc(json);setCnzMap(cnzAutoMap(cols));setCnzContainer(cnzExtractContainer(file.name));setCnzContainerCol("");};rd.readAsArrayBuffer(file);}e.target.value="";},[]);
  const cnzBuild=useCallback(()=>{if(!cnzSrc)return[];return cnzSrc.map(row=>{const out=new Array(CNZ_TOTAL).fill("");if(cnzContainerCol&&cnzContainerCol!=="-- Not Mapped --")out[0]=row[cnzContainerCol]||"";else out[0]=cnzContainer;for(const[fn,fd]of Object.entries(CNZ_FIELDS)){if(fn==="container_id")continue;if(cnzMap[fn])out[fd.col]=row[cnzMap[fn].col]||"";}CNZ_STATIC.forEach(s=>{out[s.col]=s.value;});return out;});},[cnzSrc,cnzMap,cnzContainer,cnzContainerCol]);
  const cnzExport=useCallback(()=>{const out=cnzBuild();if(!out.length)return;const wb=XLSX.utils.book_new();XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet(out),"Sheet 1");XLSX.utils.book_append_sheet(wb,XLSX.utils.aoa_to_sheet([]),"Sheet2");XLSX.writeFile(wb,`CNZ_Import_${cnzFile.replace(/\.[^.]+$/,"")}.xlsx`);},[cnzBuild,cnzFile]);

  const [winW,setWinW]=useState(typeof window!=="undefined"?window.innerWidth:1920);const [winH,setWinH]=useState(typeof window!=="undefined"?window.innerHeight:1080);
