            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{color:ia?C.cyan:C.text,fontSize:12,fontWeight:700}}>{n}</span><Trash2 size={12} color={C.red} style={{cursor:"pointer",opacity:0.6}} onClick={(e)=>{e.stopPropagation();if(confirm(`Delete ${n}?`)){const u={...skuClients};delete u[n];saveSku(u);if(skuActive===n)setSkuActive("");}}}/></div>
